#define S0 4
#define S1 5
#define S2 6
#define S3 7
#define OUT 8
void setup() {
  Serial.begin(9600);
  pinMode(S0, OUTPUT); pinMode(S1, OUTPUT);
  pinMode(S2, OUTPUT); pinMode(S3, OUTPUT);
  pinMode(OUT, INPUT);
  digitalWrite(S0, HIGH); digitalWrite(S1, HIGH); // 100% scale
}
int readColor(int s2, int s3) {
  digitalWrite(S2, s2); digitalWrite(S3, s3);
  return pulseIn(OUT, LOW);
}
void loop() {
  int r = readColor(LOW, LOW);    // Red
  int g = readColor(HIGH, HIGH);  // Green
  int b = readColor(LOW, HIGH);   // Blue
  Serial.print("R:"); Serial.print(r);
  Serial.print(" G:"); Serial.print(g);
  Serial.print(" B:"); Serial.println(b);
  delay(500);
}
